INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_414737','Від Синього Дону до Сивиx Карпат','Музика: Михайло Гайворонський Слова: Олекса Кобець','uk','ukrainian_peoples_republic_1917_1921',NULL,'1917','1. У мандри. Збірник українських пісень для пластової молоді. - Мельбурн - Аделаїда, 1981. 2. http://www.vesna.org.ua/txt/bodnaruki/mds/13.html','*Варіанти в''язок подані за джерелом 1. У ньому відсутня третя в''язка. Наша пластова молодь залюбки співає чудову бадьору маршову пісню "Від синього Дону до сивих Карпат...", не знаючи здебільшого, що автором її є письменник Олекса Кобець, а музику до неї склав Михайло Гайворонський, композитор УСС. Своїм змістом і своєю мелодією вона дуже припала до серця української молоді і стала вже на свій лад майже ародною. Її понесла наша молодь з собою на чужі континенти, в широкий світ, і в ній оспівує найсвятіші ідеали народу, як оспівав їх поет Кобець у 1917 році, перебуваючи у Фрайштадському таборі полонених. Напевно не знав автор, живучи пізніше в умовах підсовєтської дійсности, що за Збручем його пісня стала неначе другим нашим національним гімном. http://www.vesna.org.ua/txt/bodnaruki/mds/13.html Акорди підібрано за джерелом 1. Іще живі та здорові Всі Родичі Гарбузові. Тримаймось Звичаю рідного. Як мислиш порами року — сій, як мислиш роками — сади дерева, а як мислиш віками — рости дітей співаючи. Народна мудрість Підбір акордів: bohdanko (pisni.org.ua)','Від Синього Дону до Сивиx Карпат
Одна нероздільна Родина
Без панства, без рабства, насильства і зрад, |
Вільна, незалежна Вкраїна.                   | (2)

Ми діти Народу широкиx степів,
Ми все є готові до бою
За Правду, за Волю, за Віру батьків          |
Прапор наш леліє Горою.*                     | (2)

В нас крила орлині і бистрий наш літ,
І бистре соколине око,
До бою зірвемось, як буря, у мить,           |
І стяг піднесемо високо.                     | (2)

Дочки/Сини України ставаймо сильні
Тримаймось Звичаю рідного
Зберем з поля чистого квіти-пісні            |
В вінок України вільної.**                   | (2)

Від Синього Дону до Сивиx Карпат
Одна нероздільна родина
Без панства, без рабства, насильства і зрад, |
Вільна, незалежна Вкраїна.                   | (2)
*Варіант в''язки:
Ми діти Вкраїни, широкиx степів,
Ми завжди готові до бою.
За Правду, за Волю, за Славу батьків         |
Прапор наш леліє Горою.                      | (2)

**Варіант в''язки:
Сини України! Ставаймо вільні
Під Прапор Ідеї одної
Зберем з поля рідного квіти рясні            |
В вінок України вільної.                     | (2)

Акорди:
Від Синього Дону до Сивиx Карпат
Одна нероздільна Родина
Без панства, без рабства, насильства і зрад, |
Вільна, незалежна Вкраїна.                   | (2)','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:plastovi'', ''Гимни та марші'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_414737'), datetime('now')),datetime('now'));
