INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4160137','Марш Тарасівців','Музика: Олесь Аргат Слова: Олесь Аргат','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Не мій кумир лякливий кріт
Я хочу жити хочу здобувати світ.
На цій землі я залишити хочу слід
Я втілить мушу заповіт.

Не йти до зайди на поклон
І не чекать свого народу похорон
І говорить лише мечем, списом зі злом
Іти шукать Новий Вогонь.

Не скраю я зведу свій дім
Аби в запічку було затишно унім
Серед руїн і богом проклятих осель
Свою зведу я цитадель.

На вітер слів я не пущу
Бо спрагла діл, земля як в засуху дощу
І моя мрія духу не полон
А лиш наказ, лише закон.

Самому знаю не дійти
Хтось має право довести нас до Мети
І я до послуху своїй старшині звик
Для когось я так само Провідник.

На смоїдство тратить час
Нам не велів Бог нам не велів Тарас
Лише зусиллям волі, дорогой ціной
Захочу й буду я Герой !!!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4160137'), datetime('now')),datetime('now'));
