INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4181838','Машинґвери','Музика: Андрій Менцак Слова: Андрій Менцак. Виконує: Володимир Вермінський, Андрій Менцак','uk','ukraine_1991',NULL,NULL,NULL,'Музичний відеокліп "Машинґвери", присвячений боротьбі Української Повстанської Армії, знято за ініціативи та за фінансового сприяння власника магазину зброї та спорядження "Штурм" Володимира Правосудова та товариства пошуку жертв війни "Пам''ять". Автор і виконавець пісні Андрій Менцак запис пісні проводив на студії "Галицький заповідник". Зйомки кліпу проводилися у селах Загір''я та Раковець Пустомитівського району Львівської області. http://www.memoria.com.ua/ Адреса на ютюбі: www.youtube.com/watch?v=ysor3GVrFLs Акорди надав: Fill13 Підбір акордів: Fill13','1.
Ми сьогодні сюди не запрошені,
не чекали нас тут.
Машингвери свої запорошені
нам не випадуть з рук.

Приспів:
Машинґвери, Штурмґевери,
відкривай, мерзота, двері!
Ми прийшли вже, гейя, гойя.
Кров схолоне, буде лятись.
Хтось зависне на гілляці.
Ми прийшли вже, гейя, гойя.

2.
Ми питаєм, можливо, останній раз,
хто боївку продав.
Чи не має часом серед смертних вас,
хто запроданцем став?

3.
За боївку наварено, змелено,
але зрадник мовчав.
За вікном на горісі зеленому
вітер ноги гойдав.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4181838'), datetime('now')),datetime('now'));
