INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_42434','Верше','(Ой верше, мій верше). Українська народна пісня. Виконує: Ансамбль Львівського Університету "Черемош", Illaria','uk','ukraine_before_1917',NULL,NULL,'Книга "Пісні "Черемоша"','Підібрав Ігор Ковальчук.','------------------3-------------------------3-----
