INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_429737','Пане підпоручнику','Музика: Олександр Смик Слова: Олександр Смик. Виконує: Наталя Криничанка, Володимир Вермінський','uk','ukraine_1991',NULL,NULL,'1. Аудіо-CD "Олександр Смик. "Червоне... Чорне... Біле...". Ч.1. (2001). 2. Картавий П. Співана поезія як художнє віддзеркалення Всесвіту.- Суми, 2002.','Текст записано на слух. Виправила й доповнила Наталя Криничанка. Акорди підібрано на слух, спрощено. * Тут акорд D7 є тільки перед повтором. ** Інший варіант тексту [2]: Якщо тебе вб''ють, кинуть під паркан. Ця пісня увійшла в аудіо-альбом (CD) "Я кохаю цього чоловіка". З питаннями щодо придбання альбому та з пропозиціями щодо музичної співпраці звертайтесь за адресою etra@ukr.net або залишайте повідомлення на сторінці "Українські пісні: Наталя Криничанка". Підбір акордів: bohdanko (pisni.org.ua)','Пане підпоручнику, вже зійшла зоря,
Час гуляти вовку битим шляхом.
Заспівали кулі; десь співа й твоя,
Gm    A7   Dm    (D7)*
Шляк би її трафив.

Ніч, холодна ніч, ніби й не було.
Серед цих пожеж знов серцю зимно.
Пане підпоручнику, знало все село:  |
Gm   A7    Dm    (D7)*              | (x2)
Я тобі дружина.                     |

Повінчав нас ліс віночком із трав,
В головах стояли білі коні.
Пане підпоручнику, ти тоді казав:  |
"Бог нас оборонить..."             | (x2)

Твій холодний труп кинуть під паркан - **
Кров, як вишиванка, під мундиром...
Пане підпоручнику, мене не злякать -  |
Піду до Сибіру...                     | (x2)

Пане підпоручнику, вже зійшла зоря,
Час гуляти вовку битим шляхом.
Заспівали кулі; десь співа й твоя,  |
Шляк би її трафив.                  | (x2)','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_429737'), datetime('now')),datetime('now'));
