INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4480939','Десь собі','Музика: Dance Monkey Слова: Роман Стахнів','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує гурт МАЙБУТНЄ (альбом: Кавери).','[Intro]
Десь лунають крики, десь лунає сміх.
Десь любов панує, десь панує гріх.
Знаю,               D
Кожен має ціль, має мету,
Але не кожен має в серці доброту.
Приспів:
У-я                D
Хочу, хочу, хочу, щоби всі:
Мамусі, татусі, дідусі і бабусі
Були                      D
Разом, разом, разом із дітьми
І нам допомагали до мети іти!
І ще
Десь собі, десь собі, десь собі кожен з нас
Думає про те, що є на все в житті свій час.
Потім просим:
Дай мені, дай мені, дай ще один шанс
Побути разом із батьками ще хоч раз!
А коли ми вже дорослими будем,
Часу не буде, але буде купа проблем.
Ми не встигнемо моргнути, як життя
Забере наших батьків у небуття...
Приспів.
Речитатив:
В житті у нас є дві людини!
Нема й не буде їм заміни,
Бо це вони - це мама й тато,
Така в них доля - нас чекати!
На кожну звісточку і слово
У них це втілення любові,
Вони нас приймуть і зігріють,
Їм тяжко, а в очах надія
На те, що ми щасливі будем -
Найрідніші в світі людям,
Бо ми - радості хоч трохи
В їх тяжкі батьківські руки!..
Приспів.','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4480939'), datetime('now')),datetime('now'));
