INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_485436','Там, в горах Карпатах','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Всі в''язки повторюються на зразок першої.','H
Там в горах Карпатах
Сумні дни настають.
H
Бо юж наші лемки
Гори опущають.
Там в горах Карпатах
Сумні дни настають.
H
Бо юж наші лемки
Гори опущають.

Гори опущають,
Але не з радости,
Бо достали розказ
Од пана старости.

Як ми виїжджали,
То дзвони дзвонили.
З великим ми жальом
Село опустили.

Прийшли ми на захід,
Стали ся дивити,
Ой, Боже, наш, Боже,
Як ту будем жити.

Поля не орани,
А ми не сіяли.
Лем тоті будинки
Порозвалювани.

Гори наші, гори,
Сиротами стали.
Нашими ренками
Захід засіяли.

Гори наші, гори!
Ми вас не забудем.
Попля життя наше
Споминати будем.','[''pisni.org.ua'', ''cat:43'', ''cat:istorychni'', ''cat:lemkivski'', ''Еміґрантські пісні'', ''Історичні пісні'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_485436'), datetime('now')),datetime('now'));
