INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_613374','Била мене мати','Українська народна пісня. Виконує: Візерунки шляхів','uk','ukraine_before_1917',NULL,NULL,'1. Червоная калинонька. Українські народні пісні. Пісенник. Упорядник В. М. Пономаренко. - К.: Музична Україна, 1988. - 200 с.','Тональність D у доданих файлах відмінна від тональності F поданих акордів. Текст виправлений за джерелом 1. * У версії гурту "Візерунки шляхів": "півні"','Била мене мати
