INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_613673','А я все дивлюся, де моя Маруся','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Якби мені сивий кінь,
G
Я сідельце маю,
Поїхав би за Дунай,
Там дівчину маю.

Приспів:
А я все дивлюся,            |
C                           |
Де моя Маруся,              |
Dm                          | (2)
А я все дивлюся,            |
Де ж ти моя Маруся.         |

Як приїхав за Дунай,
Як прийшов до хати,
Стара баба, старий дід,
Ще й дівка кирпата.

Приспів.

Як прийшов я в хату,
Дали мені сісти,
Поставили бараболі,
Не лупленої їсти.

Приспів.

А я тії бараболі,
По столі качаю,
На полиці паляниці,
Я до них моргаю.

Приспів.

Погасили каганець,
Полягали спати,
Я за тії паляниці,
Та й давай тікати.

Приспів.

Не попав у двері я,
А в стовп головою,
Отаке то приключилось,
Лишенько зі мною.

Приспів.

Як тікав я через тин,
Через перелази,
Били мене ціпом, ціпом,
аж чотири рази.

Приспів.','[''pisni.org.ua'', ''cat:dances'', ''cat:narodni'', ''cat:polky'', ''cat:zhartivlyvi'', ''Пісні до танцю'', ''Народні пісні'', ''Польки'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_613673'), datetime('now')),datetime('now'));
