INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_622972','Одна калина','Музика: Руслан Квінта Слова: Віталій Куровський. Виконує: Софія Ротару, Василь Білоцерківський','uk','ukraine_1991',NULL,NULL,NULL,'Виконує: Софія Ротару, в оригіналі тональність вища за подану на 1,5 тона. Підбір акордів: Kolivan','Вступ:  Dm Am  E  Am
Сумно, сумно, аж за край,
Не дивись на мене,
Грай, музико, грай.
Зимно, зимно на душі
Забирай, що хочеш
Тільки залиши...
Приспів:
Одну калину за вікном,
Одну родину за столом,
Одну стежину, щоб додому йшла сама.
Одну любов на все життя,
Одну журбу - до забуття.
І Україну, бо в нас іншої нема!!!
Сумно, сумно, аж за край.
Так чого ж ти плачеш?
Грай, музико, грай!
Крапля горя не заллє,
Наливай козаче, бо у нас ще є...
Приспів.
Сумно, так і не засну,
Краще буду думать про свою весну,
Та й піду за небокрай,
Вперше, як востаннє -
Грай, музико, грай:
Про ту калину за вікном,
Одну родину за столом,
Одну стежину, щоб додому йшла сама.
Одну любов на все життя,
Одну журбу - до забуття.
І Україну, бо в нас іншої нема!!!','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_622972'), datetime('now')),datetime('now'));
