INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_624477','Україна - релігія','Музика: Олександр Смик Слова: Олександр Смик. Виконує: Олександр Смик','uk','ukraine_1991',NULL,NULL,'Аудіо','Текст і акорди записано на слух з аудіо. Тональність оригінальна. Підбір акордів: bohdanko@pisni.org.ua','В час великого здвигу
все так складно і просто.
Настає
вирішальний момент.
Україна - релігія,
їй потрібен апостол,
їй потрібен апостол,
не президент.

Український бо час -
це історія вічності.
На десятому колі
окреслили крес.
Це релігія нас,
ми хрестами помічені;
перший хрест над Дніпром -
це Андріївський хрест.

Кричимо де не слід,
що Європа спасенна,
і жила, і жиє
доки є.
Не дві тисячі літ
ойкумена блаженна;
залишилось лише
поважати своє.

Україна - релігія,
Україна - молитва.
Вже у кожнім селі
кам''яніє Тарас.
Нам потрібен апостол -  |
Gm        |
ми готові до битви -    |
Cm             | (x2)
...той апостол,         |
що виведе нас.          |','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_624477'), datetime('now')),datetime('now'));
