INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6286991','Мандрівці ми','Музика: В. Божик Слова: В. Софронів-Левицький','uk','ukr_ssr_1919_1991',NULL,'1946','Пластовий співаник "В дорогу", 1947 р.','Мандрівна пластова пісня, складена для пластових гуртків в Інґольштадті 1946 року.','Прощайте нам, хатні пороги,
Нам душно в сірих мурах міст,
Нас манять в даль святі дороги,
Лісів зелена благовість.
Мандрівці ми, сини природи,
Мандрівці ми, ловці пригод,
Бадьорий дух,
Воля і рух
На шляху трудів і невигод.
В нас очі широко розкриті
На чар природи, на красу,
У нас серця добром налиті,
Співаєм пісню молоду:
Мандрівці ми...
А як вже ніч над поле злине
І зійде місяць понад ліс,
Тоді кладемось на спочинок
Під наш старий "Великий віз"...
Мандрівці ми...','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6286991'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6286991','Мандрівці ми','Прощайте нам, хатні пороги,
