INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_63178','Чорні круки','Музика: Ігор Особік Слова: Ігор Особік. Виконує: Андрій Хавунка','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки. Львів, 2000.',NULL,'Чорні круки, не кружіте наді мною.
Вони хочуть моєї крови, вони хочуть моєї муки.     | (2)

Сил нема мені піднятись, певно тяжко потято в бою.
А довкола мої браття - чорні чуби, чорні брови.    | (2)

Приспів:
Та іще не все скінчилось,
Ще дзвенять наші кривулі.
То козаки там за яром,
"Чуєте, браття?"
E
"Чуєм, чуєм..."

Руки й ноги, як не мої, і рамена ніц не гідні.
Вони мені ще так потрібні, мамцю земле, ти загой їх. | (2)

Приспів:
А за яром крики: "Слава!"
Перемога, дяка, слава Богу.
Ще й над нашим сонце засяє краєм,
І запануємо ми, браття, у сторонці.

Чорні круки!
Наді мною ви так р''яно не кружіте.
Бо я хочу і буду жити,              |
Україні буду служити.               | (2)','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_63178'), datetime('now')),datetime('now'));
