INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6348','Писаний Камінь','Музика: Євген-Орест Садовський Слова: Пластовий гурток ім. М. Дужого. Виконує: Журборіз','uk','ukraine_1991',NULL,NULL,'1. Пісневир. Молодіжний співаник. Львів 2000. 2. Самвидавний туристський пісенник "Де гори Карпати, де Писаний Камінь". - Літо, 1982.','*Подані акорди відповідають доданим файлам midi-мелодії і нот, у яких відмінна тональність.','Де гори Карпати,
Де Писаний Камінь,
Туман по долині пливе.
Тебе, рідний краю,
До болю кохаю,
Навік полонив ти мене.
Гей, гей...
Такому коханню,
Повік не зів''яти,
А в серці завжди берегти.
В Карпати, в Карпати,
В далекі Карпати
Лети, моя пісне, лети.
Гей, гей...
Лети в Чорногору,
В її полонини,
Спочинь на ялиці стрункій,
Вдар громом об скелю,
Котись по долині,
Верхами неси голос мій.
Гей, гей...
Де гори Карпати,
Де Писа_ний Камінь,
Туман в полонинах пливе.
Тебе, рідний краю,        |
Dm                    |
До болю кохаю,            |(2)
Навік полонив ти мене.    |
Гей-гей, гей-гей, гей-гей, гей-гей,
Гей-гей, гей-ге-е-е-е-ей, гей-гей...','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:plastovi'', ''Пісні про красу природи'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6348'), datetime('now')),datetime('now'));
