INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_642','Гей-гу, гей-га - таке то в нас життя','Музика: Тарас Чача-Крушельницький Слова: Тарас Чача-Крушельницький. Виконує: Тарас Чубай, Скрябін, Володимир Турець','uk','ukr_ssr_1919_1991',NULL,'1930','1. Літопис УПА. 1996-1997.– Т.25: Пісні УПА 2. Аудіо-CD "Тарас Чубай і Скрябін. "Наші партизани" (2000) 3. Співаник Лицаря. Видання Куреня УСП ч.15 "Орден Залізної Остроги" ім. Святослава Завойовника, Пласт – НСОУ.– Київ–Львів, 2004','Варіант 1 - це повстанський переспів пластової пісні. Варіант тексту взято з музичного проекту "Наші партизани" [2]. У первісному варіанті - пісня 3-го Куреня Старших Пластунів "Лісові Чорти", створена під час їхньої мандрівки човнами на Поліссі 1930 року. Варіант 2 взято із джерела 2. Були поширені й інші варіанти тексту (із незначними відмінностями). Див. джерело 1. У джерелі 2 оригінальні акорди такі: 1: | Gm Cm D7 Gm | Cm Gm D7 | D7 Gm D7 Gm | F A# F A# | D7 Gm | Gm | 2: | Cm Gm D7 | Cm Gm D7 |... Підбір акордів: bohdanko','Варіант 1:
Гей-гу, гей-га - таке то в нас життя:
Наплечники готові - прощай, моє дівча.
Сьогодні помандруєм - не знаємо самі
Де завтра заночуєм: чорти ми лісові!
Гей-гу, гей-га - чорти ми лісові!
Гей-гу, гей-га.
А як прийдеться стати зі зброєю в руках,
Gm       Dm         A7 ...
Бандера поведе нас - замає гордо стяг:
І сипнемо сто-тисяч у зуби сатані,
А решта люциперу - чорти ми лісові!
Гей-гу, гей-га - чорти ми лісові!
Гей-гу, гей-га!
Як впадеш, стрільче, в пастку чи зловишся на дріт,
На всі питання ката давай один одвіт:
Що до ОУН належав - а вождем був Євген -
Щоб слава залунала далеко ген-ген-ген...
Гей-гу, гей-га - далеко ген-ген-ген...
Гей-гу, гей-га.
Прапор червоно-чорний це наше знамено:
Червоне - це кохання, а чорне - пекла дно.
Усі дівчата знають пекельні барви ці -
Забути їх не можуть, чорти ми лісові!
Гей-гу, гей-га - чорти ми лісові!
Гей-гу, гей-га!
Варіант 2:
Гей-гу, гей-га, таке-то в нас життя.
Наплечники готові, прощай, моє дівча!
Сьогодні помандруєм. Не знаємо й самі,
Де завтра заночуєм, чорти ми лісові!
Гей-гу, гей-га, чорти ми лісові!
Прапор червоно-чорний - це наше все добро,
Червоне - це кохання, а чорне - пекла дно.
Усі дівчата знають пекельні барви ці,
Забути їх не можуть. Чорти ми лісові!
Гей-гу, гей-га! Чорти ми лісові!
А як прийдеться стати зі зброєю в руках,
Маршалок поведе нас, замає гордо стяг!
І сипнемо сто тисяч у груди сатані,
Люциперові решту! Чорти ми лісові!
Гей-гу, гей-га! Чорти ми лісові!
Як впадеш в вовчу пастку, чи зловишся на дріт,
На всі питання ката давай один одвіт:
"Ми до ОУН належим, а батько наш Євген,
І слава України полине ген-ген-ген!
Гей-гу, гей-га, полине ген-ген-ген!"','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:manrivni'', ''cat:patriotic'', ''cat:plastovi'', ''cat:povstanski'', ''Гимни та марші'', ''Пісні на мандрівну тематику'', ''Патріотичні пісні'', ''Пластові пісні'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_642'), datetime('now')),datetime('now'));
