INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_646075','Пісня Вічного Вогню','Музика: Сергій Солоний Слова: Олесь Бердник. Виконує: Сергій Солоний','uk','ukraine_1991',NULL,NULL,'1. Аудіо-CD "Дух не вмирає, дух не згаса..." http://www.umka.com.ua/ukr/catalogue/1466/ 2. http://www.berdnyk.narod.ru/virshi.htm','Текст подано за джерелом 2, може відрізнятися від варіанту, який є у пісні. Акорди підібрано на слух за аудіо [1]. Оригінальні тональність: Cm. Підбір акордів: bohdanko (www.pisni.org.ua)','Палає небокрай,
Світанкова пора...
Вставай, вставай, вставай -
Горить Нова Зоря!

І хто б де не умер -
Від зради чи в борні -
Воскресніте тепер
У Вічному Вогні!

Встаньте, убиті
Сестри й брати!
Брама відкрита
В нові світи!

Смерті немає -
То лиш мара,
Дух не згасає,
Дух не вмира!
Дух не згасає,
Дух не вмира!

Клубиться чорний дим,
Планета у вогні,
Над обрієм земним
Потвори навісні.

Та повстають сини,
Щоб подолати лють,
На вічний мир вони
Всім руки подають!

Вирує лан життя,
І голуби над ним...
Немає вороття
Руйнаторам сліпим,

Бо діти вояків,
Що впали у борні,
Ідуть з усіх країв
У лави вогняні!','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_646075'), datetime('now')),datetime('now'));
