INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_669477','Калина','Музика: Трансформер Слова: Тарас Шевченко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Зацвіла в долині
C
Червона калина
G
Ніби засміялась
D
Дівчина дитина
Любо любо стало
Пташечка зраділа
І защебетала

Почула дівчина,
І в білій свитині
З біленької хати
Вийшла погуляти
У гай на долину.
І вийшов до неї
З зеленого гаю
Козак молоденький;
Цілує, вітає,
І йдуть по долині
І йдучи співають.
Як діточок двоє,
Під тую калину
Прийшли, посідали
І поціловались.

Якого ж ми раю
У Бога благаєм?
Рай у серце лізе,
А ми в церкву лізем,
Заплющивши очі, —
Такого не хочем.
Сказав би я правду,
Та що з неї буде?
Самому завадить,
А попам та людям
Однаково буде.','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_669477'), datetime('now')),datetime('now'));
