INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_676050','Радуйся, Маріє',NULL,'uk','ukraine_1991',NULL,NULL,'1. пісенник для християнської молоді "Боже, мій Боже, з тобою пісня..."','пісенник для християнської молоді "Боже, мій Боже, з тобою пісня..."','C
Раз зайшов я в храм старенький
Та ікону там побачив.
На іконі ангел з неба
Так вітає Божу Матір.

Приспів:
Радуйся, Маріє, я перед Тобою.   |
Радуйся, Маріє, Господь з Тобою. |
Радуйся, Маріє, повна благодати. |
Радуйся, Маріє, Божая Мати.      | (2)

Тихо-тихо в церкві стало,
Серцем слухаю я знову:
Чи усе мені це здалось,
Чи провадить хтось розмову?
Чую, як шепоче Діва,
А на серці тривога.
Ангел Їй: "Не бійсь, Маріє,
Бо знайшла Ти ласку в Бога!"

Приспів.

Ти з''явився, як людина,
А звіщаєш слова Божі.
Як же я народжу Сина,
Коли я не знаю мужа?
"Коли Бог захоче того,
То зміняє лад природи,
Він пошле Духа Святого,
І Ісуса Ти народиш".

Приспів.

"Я сповнити все готова
І в покорі все приймаю.
Хай здійсниться Твоє слово,
Й душа Бога величає".
Я залишив храм старенький,
Та ікону в серці маю.
І спішу усім сказати,
Як Марія нас кохає.

Приспів.

Радуйся, радуйся Маріє           | (4)
Радуйся... Аве Марія...','[''pisni.org.ua'', ''cat:christian'', ''cat:do-bohorodyci'', ''Пісні на християнську тематику'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_676050'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_676050','Радуйся, Маріє','C
