INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_673542','Львів *','(Tyle jest miast). Музика: M. Hemar Слова: M. Hemar. Виконує: Піккардійська Терція','uk','ukraine_1991',NULL,NULL,NULL,'Пікардійська Терція (укр., пол.) Michał Bajor (пол.) Zofia Terne (пол.) Підбір акордів: ppa','Трудиться вигнане серце
В пошуках твоїх снів.
О місто людей веселих
І добрих співучих слів.
C
З зелених садів
Лине цей спів,
Бути молодим - то у Львові.
Всюди панує слушна оказія
Для веселощів, сліз, для безсоння й фантазій.
C
Як в небі звізд -
Стільки є міст,
Та знайдуть ці слова тебе знову.
Йди де бажаєш,
Чини все так як знаєш,
Хочеш в молодість знов - їдь до Львова.
Йди де бажаєш,
Чини все так як знаєш,
Хочеш в молодість знов - їдь до Львова.
У ратуші леви камінні
Варту при брамі несуть.
Знають вони, що незмінні
Юні мрії і цвіт бузку.
Музика грає,
Серце стискає,
Щастя хочеш - вернися до Львова.
Всюди панує слушна оказія
Для веселощів, сліз, для безсоння й фантазій
Стільки є міст,
Як в небі звізд,
Час позначив нас срібним покровом.
Йди, де бажаєш,                         |
Чини все так як знаєш,                  | (2)
Хочеш в молодість знов - їдь до Львова. |','[''pisni.org.ua'', ''cat:halycki'', ''Пісні з Галичини'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_673542'), datetime('now')),datetime('now'));
