INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_699757','Як у нас на Україні','Українська народна пісня. Виконує: Катерина Бужинська','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Тече річка-невеличка,
Через гори, через гай.
Рано вранці небо кличе,
G
Вставай сонце - вставай.
C
Розбуди усе навколо,
Хай почує рідний край.
Пісню гарну, серцю милу,
E
Добрим людям співай.

Приспів (2):
Як у нас на Україні -
E
Всі лани квітучі,
Так у нас на Україні -
E
Люди всі співучі.
Хай же щастя в домі
І пісень багато,
Бо без пісні в Україні
Не буває свята.

Тече річка в синє море,
Прокладає собі путь.
І малі струмки прозорі,
Сил мені додають.

По землі вода гуляє,
Напуває рідний край.
Все довкола оживає,
Співай земле, співай.

Приспів.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_699757'), datetime('now')),datetime('now'));
