INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_71044','Пустельник','Музика: Володимир Якимець Слова: Дзвінка Сумарук. Виконує: Піккардійська Терція','uk','ukraine_1991',NULL,NULL,'Пісневир. Молодіжний співаник. Львів 2001.',NULL,'Є на світі цім   пустельний берег,
Там живе пустельник   із моїм ім’ям.
Не шумлять на березі осока і верби —
Випалена і мертва кам’яна земля...
Кам’яна земля.

Приспів:
Має той пустельник хату із каміння,
Ложе кам’яне, свічку кам’яну,
Крила кам’яні приросли корінням
До закам’янілого, вицвілого сну.

Я не знаю, хто ви — смерть чи воскресіння,
Я не знаю, що ви принесли мені.
Доторкніться поглядом до того каміння,
Може з нього зацвітуть вам мої пісні...
Вам мої пісні вам мої пісні.

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_71044'), datetime('now')),datetime('now'));
