INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_713941','Гай, зелений гай','Музика: Олександр Злотник Слова: Юрій Рибчинський. Виконує: Назарій Яремчук, Смерічка, Таїсія Повалій, Василь Зінкевич, Зоряна Юдін','uk','ukraine_1991',NULL,NULL,'Українські пісні/ уклад. О.В.Зав''язкін. - Донецьк:"Бао", 2003. - 512 с.','Am7/5- [x 0 1 0 1 3]','Там, де зустрів тебе, там шумить і нині
Гай, зелений гай
Там полюбив, як я, твої очі сині
Гай, зелений гай
Там полюбив, як я, твій веселий голос
Гай, зелений гай
Там ти спитала: "що буде з нами, любий,
Як мине розмай?"
Приспів:
Ти щаслива будеш,    (3)
Грай, музико, грай!
Am7/5-
А мене забудеш,
А мене забудеш,
А мене забудеш
Грай, музико, грай!
Можеш все забути     (3)
Тільки пам''ятай
Am7/5-
Зоряну дорогу,
Зоряну дорогу,
Зоряну дорогу
В гай, зелений гай.
Як я тебе кохав -
Пам''ятати буде гай, зелений гай,
Що я тобі казав -
Не розкаже людям гай, зелений гай.
А як прийдуть осінні, холодні хмари
В гай, зелений гай
Хай на твоїм весіллі
Лунає пісня, ллється через край.
Приспів.','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_713941'), datetime('now')),datetime('now'));
