INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7198363','Бог посилає все для нас, я щасливий',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Бог посилає все для нас, я щасливий!
І сонце, й дощик в добрий час, я щасливий!
Люблю я трави запашні, барвисті квіти навесні,
А восени плоди смачні, я щасливий!

І тато й мама в кожний час, я щасливий!
Завжди турбуються про нас, я щасливий!
З любов''ю їжу подають,
І новий одяг нам дають,
Ласкаво в ліжечко кладуть, я щасливий!

Про мене дбає добрий Бог, я щасливий!
Він захищає від тривог, я щасливий!
В країні вічній, неземній
Господь по милості Своїй
Для мене дім дарує Свій, я щасливий!','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7198363'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7198363','Бог посилає все для нас, я щасливий','Бог посилає все для нас, я щасливий!
І сонце, й дощик в добрий час, я щасливий!
Люблю я трави запашні, барвисті квіти навесні,
А восени плоди смачні, я щасливий!

І тато й мама в кожний час, я щасливий!
Завжди турбуються про нас, я щасливий!
З любов''ю їжу подають,
І новий одяг нам дають,
Ласкаво в ліжечко кладуть, я щасливий!

Про мене дбає добрий Бог, я щасливий!
Він захищає від тривог, я щасливий!
В країні вічній, неземній
Господь по милості Своїй
Для мене дім дарує Свій, я щасливий!');
