INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7200848','Ісус, Ти - найкращий Друг',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ісус, Ти - найкращий Друг,
В час, коли моє серце плаче,
Я до Тебе в молитві йду,
Ти поможеш мені, мій Пастир.

Для душі мій спокій в Тобі,
Ти - відрада моя, Спаситель,
Підкріпляєш у боротьбі,
Вірний Друг і душі Втішитель.

C
Я любов''ю Твоєю живу,
І вона моє серце гріє.
Щиро, Спасе, Тебе я люблю,
І ніхто вже Тебе не замінить.

Ти Один розумієш все
І думки всі таємні знаєш,
Ти зі мною, і в кожну мить
Потішаєш і підкріпляєш.
Хай полине подяка Тобі
За щедроти і вічну милість.
Ісус, Ти - Спаситель душі,
Ти і щастя моє, і радість!','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7200848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7200848','Ісус, Ти - найкращий Друг','Ісус, Ти - найкращий Друг,
В час, коли моє серце плаче,
Я до Тебе в молитві йду,
Ти поможеш мені, мій Пастир.

Для душі мій спокій в Тобі,
Ти - відрада моя, Спаситель,
Підкріпляєш у боротьбі,
Вірний Друг і душі Втішитель.

C
Я любов''ю Твоєю живу,
І вона моє серце гріє.
Щиро, Спасе, Тебе я люблю,
І ніхто вже Тебе не замінить.

Ти Один розумієш все
І думки всі таємні знаєш,
Ти зі мною, і в кожну мить
Потішаєш і підкріпляєш.
Хай полине подяка Тобі
За щедроти і вічну милість.
Ісус, Ти - Спаситель душі,
Ти і щастя моє, і радість!');
