INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_724363','Небо України','Музика: Едуард Драч Слова: Едуард Драч. Виконує: Едуард Драч','uk','ukraine_1991',NULL,NULL,'1. Аудіо-альбом "Едуард Драч. "Небо України" (1993-1998). 2. http://www.bulava.org/art/drach/nebo/nebo.html','Текст і акорди взято з джерела [2]. Уточнено й доповнено за джерелом [1]. * Тут у джерелі [2] замість акорда E7* є акорд E#7, що, очевидно, є помилкою. Загалом акорди тут подано занадто спрощено, тому вони потребують подальшого уточнення й доповнення.','О- ой, ти - як море синє,
О- ой, небо України.
Хмари, як ті хвилі,
Ген, - на небосхилі
І пливуть поволі,
Наче хвилі в морі.
І завжди ти різне:
E7*                Am
То, як море - грізне,
А то й світиш птахам
Ти чумацьким шляхом.

Ой, скільки в тебе сині,
Ой, небо України!
Як вбере світання
В золотаве вбрання,
Ти то сяйвом сяєш,
То вогнем палаєш.
І завжди ти різне:
то, як море - грізне
А то й світиш птахам
Ти чумацьким шляхом.

Ой, скільки в тебе сині,
Ой, небо України!
Як тебе згадаю
Я в чужому краю,
Лину я до тебе,
України небо!
Та й на ясні зорі,
Та й на тихі води,
Серце птахом лине
На мою Вкраїну!

Ой, скільки в тебе сині,  |
Ой, небо України!         | (x3)

Ой, скільки в тебе сині...','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_724363'), datetime('now')),datetime('now'));
