INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7250642','Гарний козак, гарний','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Гарний козак, гарний,
Гарний на натуру,
Гарно грає, грає на бандуру,
Грає на бандуру.
Струни мої, струни,
Грайте мені стиха,
Може, козак, козак-сіромаха
Забуде свого лиха?

Приспів:
Наша слава козацькая
Не на папері писана,
Лісами, гаями, байраками
Вона заколисана
Лісами, гаями, байраками
Вона заколисана.

Та ще б і годиться
Козак-сіромаха,
Ще не заржа, ще не заржавіла
Шабля моя сваха.
Бо як натягну лук,
Брязну тятивою,
Той утече, втече з України
Всяк ворог з ордою.

Приспів.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7250642'), datetime('now')),datetime('now'));
