INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7269549','Де ж наша слава','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'із аудіозапису о.Тадея','Пісню виконує Квінтет Алилуя.','Де ж наша слава, слава кривава,
Де ж ті гетьмани, Січ﻿ і козаки?
Все кати забрали, все поруйнували,        |
