INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_749565','Апрєль','Музика: Т.І.К. (Тік) Слова: Віктор Бронюк. Виконує: Т.І.К. (Тік)','uk','ukraine_1991',NULL,NULL,NULL,'Акорди подано спрощено, дещо не міг підібрати з фортепіано Підбір акордів: AHill','Сама не подумала, нащо -
пішла і забувши про літо.
Не вернешся більше нізащо.
Повернеш назад усі квіти...
Літала, не думала в безвісті -
чекала повернення раю.
Сумними думками тверезості.
П''яніла від чорного чаю.

Приспів
Ще так далеко до зими і до морозів.
Навіщо спомини сумні, навіщо сльози.
Ще так далеко до весни або до літа.
І може хтось, але не я...
Подарить квіти.

Жодної битви не виграла -
кохання з війною зрівнявши.
А ти сама себе із дому вигнала.
У душу нічого не взявши.
Такого чудового літа,
давно вже у мене не було.
Цілий світ хотів тобі подарити,
а ти його просто не чула.
Я цілий світ хотів тобі подарити,
а ти його просто не чула.

Приспів','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_749565'), datetime('now')),datetime('now'));
