INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_75464','Дiвчина (з iншого життя)','Музика: Святослав Вакарчук Слова: Святослав Вакарчук. Виконує: Гурт "Океан Ельзи"','uk','ukraine_1991',NULL,NULL,'Аудіозапис(CD) - Океан Ельзи. Суперсиметрія. 2003; текст - http://www.okeanelzy.com','Океан Ельзи Підбір акордів: smash- flyagka@ukr.net','Не така, як інші, вона
G
і лягає спати сьогодні одна,
Але щось таке в її очах.

В неї все вже було давно,
і вона хотіла зніматись в кіно -
Дівчина із іншого життя.

Писпів:
C
Я чекав тебе, чекав,
D
Я шукав тебе, шукав -
і знайшов.
C
Твоє минуле лікував
D
і своє тобі давав
Знов і знов.

і не була в різних містах,
і вона не пише вірші у листах,
Але щось таке в її словах.

Може, в неї дивне ім''я,
Може, десь на неї чекаю не я -
Дівчина із iншого життя.

Писпів.

