INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_76969','Знаю Я','Музика: Руслана Слова: Олександр Ксенофонтов. Виконує: Руслана','uk','ukraine_1991',NULL,NULL,'текст(основа)- http://www.ruslana.com.ua','* Тут замість F# можна грати A. ** На вкладці аудіо-CD тут такий текст: "Ти не знаєш вогню, ватри вогню!" В аудіо-версії пісні після Програшу 2 йде Приспів, а далі 4 купл. і Фінал. Підбір акордів: bohdanko','Інтро (за відео-версією):
Є прекрасна земля,
Що летить у зірках
На купальських вінках,
Я заблукаю, а, може, впізнаю
Свою любов...
Знаю...

Програш 1:  Hm F#

1 купл.
Hm      G         D      F#*     Hm
Знаю я - на долині кохання нема,
Знаю я, знаю я, тільки в горах,
Hm         G       D         F#*       Hm
Де знайти джерело, що спитати в вогня
Знаю я, знаю я!   Гей-я-гей, гей-на-на-гей!

Приспів:
Знаю, що буде, і знаю, що ні,
Най це знання не зашкодить мені,
Стежка у гори тікає моя,
Там буде Сонце - і там буду Я!

Програш 1.

2 купл.
Ти не знаєш, як вітер співає для нас,
Ти не знаєш вогня, ватри вогня! **
Як на землю з гори подивитись хоч раз,
Знаю я, знаю я! Гей-я-гей, гей-на-на-гей!

Приспів 2.
(тут в 4 рядку останній акорд - G - замість Hm)

Програш 2:
(варіант з аудіо-версії:
Гей-на-на-гей!  )

Кульмінація:
Несе кохання течія,
Та уранці з сонцем втікну я!

3 купл. (подвійний)
Я не зможу забути ні вітру, ні гір,
Знаю я, знаю я,
Там, де сині вершини торкаються зір,
Буде доля моя...
Я не зможу забути ні вітру, ні гір,
Знаю я, знаю я,
Там, де сині вершини торкаються зір,
Серце лишу своє-є-є-є-є...

4 купл.
На-на-на...
Знаю я, знаю я.
На-на-на...
Знаю я, знаю я, тільки я!

Програш 1.
Фінал: F# Hm','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:manrivni'', ''Пісні про красу природи'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_76969'), datetime('now')),datetime('now'));
