INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816171','Нова радість стала *','Українська народна пісня. Виконує: Ансамбль Львівського Університету "Черемош", Оксана Білозір','uk','ukraine_before_1917',NULL,NULL,'Колядки.- Львів: Каменяр, 1990.- 64 с.','Інші варіанти тексту: * На небесах і на землі мир проповідають. ** І ми теж співаймо, Царя прославляймо. Акорди внесла Natal-ka','Нова радість стала, яка не бувала:
Над вертепом звізда ясна світлом засіяла. (2)

Де Христос родився, з Діви воплотився,
Як чоловік пеленами убого повився. (2)

Ангели співають, "слава" восклицають,
На небесах і на земли мир провозглашають. * (2)

Давид виграває, в гуслі ударяє,
Мелодійно і предивно Бога вихваляє.

І ми теж співаймо, Христа прославляймо, ***
Із Марії рожденного смиренно благаймо:  (2)

- Просимо Тя, Царю, небесний Владарю,
Даруй літа щасливії сего дому господарю. (2)

Даруй господарю, його господині,
Даруй літа щасливії нашій ненці Україні. (2)

В мирі проводити, Тобі угодити
І з Тобою в царстві Твоїм на вік віків жити.  (2)','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_816171'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_816171','Нова радість стала *','Нова радість стала, яка не бувала:
Над вертепом звізда ясна світлом засіяла. (2)

Де Христос родився, з Діви воплотився,
Як чоловік пеленами убого повився. (2)

Ангели співають, "слава" восклицають,
На небесах і на земли мир провозглашають. * (2)

Давид виграває, в гуслі ударяє,
Мелодійно і предивно Бога вихваляє.

І ми теж співаймо, Христа прославляймо, ***
Із Марії рожденного смиренно благаймо:  (2)

- Просимо Тя, Царю, небесний Владарю,
Даруй літа щасливії сего дому господарю. (2)

Даруй господарю, його господині,
Даруй літа щасливії нашій ненці Україні. (2)

В мирі проводити, Тобі угодити
І з Тобою в царстві Твоїм на вік віків жити.  (2)');
