INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816756','Тебе це може вбити','Виконує: С.К.А.Й.','uk','ukraine_1991',NULL,NULL,'аудіо','Текст записано на слух з аудіо. Частково використано текстовий матеріал з http://www.livejournal.com/users/lancik/140007.html * Тут сумнівне: "не в праві". Ймовірно, це - русизм. ** Тут можливий інший варіанти тексту: "треба бути днем... якось жити днем..." Вступ підібрав Yurii L. (best) Підбір акордів: bohdanko','Intro:
e|-7-----------8h7-----5-------8-8---------8-8-----------|
B|-8------8--------8-----7-----7----7------7--7----------|
G|-7---7---7---------7-----5---7-----7-----7---7---------|
D|------------------------------------0---------0--------|
A|-------------------------------------------------------|
E|-------------------------------------------------------|
Вступ:  G D G D
Приспів:
G
У тобі так багато сторін.
D
Я просто не розумію,
я просто хочу спитати тебе:
D
чому ти настільки красива!
G
Чому в мене ціла купа дивних речей,
D
яких я не розумію,
яких я не відкриваю тобі,
D
бо це все може вбити,
G
тебе це може вбити.
Програш 1:  G D G D
Трошки більше, ніж навхрест,
зав''язались вузлики,
і не розірвати,    і не розв''язати.
Доторкнутись до зіниць...
Я навік в тобі застиг...
Все це так спонтанно
D
і чомусь банально...
Знати, думати, себе побачити зі сторони,
C
можливо, все в житті можливо.
Приспів.
Програш 2:  G Hm C
З двадцять другої весни
я закину свої принципи;
це буває рідко,   але так помітно...
Друзі всі здуріли мов,
всіх понесло на любов,
і ніхто не вправі,
D
тут вже ніхто не в праві *
стримати чи зупинити - це ж нормально.
C
Треба бути нам... якось жити нам...**
Приспів:
G
У тобі так багато сторін.
D
Я просто не розумію,
я просто хочу спитати тебе:
D
чому ти настільки красива!
G
Чому в мене ціла купа дивних речей,
D
яких я не розумію,
я просто не відкриваюсь тобі,
D
бо це все може вбити,
тебе це може вбити,   |
Em  D  | x2
тебе це може вбити.   |
Програш 3:  G D G D | G','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_816756'), datetime('now')),datetime('now'));
