INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817373','Червона рута *','Музика: Володимир Івасюк Слова: Володимир Івасюк. Виконує: Назарій Яремчук, Василь Зінкевич, Смерічка, Софія Ротару','uk','ukr_ssr_1919_1991',NULL,'1968','текст: http://www.domivka.net/ivasyuk/pages.php?l=uk&s=songs&p=chervona_ruta','"Червона рута" — найзнаменитіша пісня Володимира Івасюка, яка, як і сам образ, давно стала символом усього найкращого, найчистішого у сучасній естраді. Її автор написав 1968 року вже студентом Чернівецького медичного інституту, а було йому тоді всього 19 років... Але це далеко не перший твір композитора. У багатющій батьковій бібліотеці юний Володя, тоді ще старшокласник, натрапив на виданий 1906 року збірник коломийок, впорядкований Володимиром Гнатюком, а там — на такі рядки: Ой ходила, говорила гільтайова мати, Назбирала троєзілля мене чарувати, Назбирала троєзілля червону рутоньку, Та й схотіла зчарувати мене, сиротоньку. Для вісімнадцятирічного музики образ червоної рути (в іншій транскрипції "черлена рута") був хвилюючою знахідкою, справжнім одкровенням. У пошуках його деталізації він багато мандрував селами, особливо гірськими, шукаючи ключ до розуміння таємничого поняття. На Косівщині знайшов новий варіант коломийки про червону руту, а на Путильщині, в Розтоках, записав легенду про загадкове чар-зілля, яке постає в народних переказах символом вічного і чистого кохання. Зберігся унікальний документ — чернетка створення тексту "Червоної рути". Ось кілька первісних варіантів строф, які незабаром облетять світ: Ти не смійся хоч раз, Не кажи, що забула, А згадай про той час, Як ти мавкою була. Що ночами в лісах Ти чар-зілля шукала, Що з вітрами, як птах, Ти колись розмовляла. Бачу я тебе в снах У дібровах зелених. По яких же шляхах Ти вернулась до мене? Спочатку хотілося надати "Червоній руті" характеру і форми балади, але твір виходив розтягнутим, композиційно недолугим. А потрібні ж були лаконізм, простота і щирість народної пісні. Володя переписував її безліч разів, шліфував текст. Коли переконувався, що вклав у пісню все, на що був здатний, відкладав її до появи нових ідей. На обласному телебаченні Івасюк мав добрих друзів: головного режисера Василя Селезінку та звукооператора Василя Стріховича, яким повідомив про дві нові пісні. Прем''єра пісень відбулася в програмі "Камертон доброго настрою". Для запису Володя запросив до студії оркестр ансамблю "Карпати" Валерія Громцева. Солісткою була молода учителька музики Олена Кузнєцова, яка володіла гарним сопрано. Стріхович із Селезінкою були дуже вимогливі. Володимир з Оленою заспівали дуетом, зробили дванадцять дублів. І ось настало свято Володиної музики та поезії. Торжество шестирічної творчої роботи — 13 вересня 1970 року. Пополудні з Театральної площі Чернівецька телестудія перед багатотисячним натовпом на всю Україну транслює "Червоною рутою" і "Водограй". На площі й сусідніх вулицях зупиняється транспорт... Після цього виступу мільйони людей вбачатимуть у піснях Івасюка вираз своїх почуттів. А тоді ще самодіяльний ВІА "Смерічка" дав цій пісні ті крила, на яких вона полетіла до людей. У виконанні "Смерічки" "Червона рута" стала піснею року в СРСР на Всесоюзному конкурсі "Пісня-71". На заключному концерті разом з Василем Зінкевичем та Назарієм Яремчуком свою пісню співав і Володимир Івасюк. (джерело: http://www.domivka.net/ivasyuk/pages.php?l=uk&s=songs&p=chervona_ruta) Підбір акордів: IhorKo','Вступ: Em | G | Am H7
Ти признайся мені,
Звідки в тебе ті чари,
Я без тебе вcі дні
У полоні печалі.
G
Може, десь у лісах
D
Ти чар-зілля шукала,
Сонце-руту знайшла
I мене зчарувала?
Приспів:
Червону руту
Не шукай вечорами, -
Ти у мене єдина,
Тільки ти, повір.
Бо твоя врода -
То є чистая вода,
То є бистрая вода
З синіх гір.
Бачу я тебе в снах,
У дібровах зелених
По забутих стежках
Ти приходиш до мене.
G
I не треба нести
D
Мені квітку надії,
Бо давно уже ти
Увійшла в мої мрії.
Приспів.','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817373'), datetime('now')),datetime('now'));
