INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_818575','Я до тебе','Музика: Святослав Вакарчук Слова: Святослав Вакарчук. Виконує: Гурт "Океан Ельзи"','uk','ukraine_1991',NULL,NULL,'Янанебібув',NULL,'Вступ.: Gm

Сьогодні світла буде менше ніж звичайно
Такою ти була на власний випускний
Сюди негайно!
Коли на сцені я стою далеко бачу
Сьогодні ти прийшла в зеленому під низ
Давати здачі...

Приспів:
Я а-а-а-а  у тебе питаю
Я а-а-а-а , а ти до мене...

Я до тебе, я до тебе, я до тебе
І ніби в  ванну налили неба
Я до тебе, я  до тебе, я до тебе
І ніби в кухні запахло небом
Я до тебе, я до тебе, я до тебе
І ніби спальня то твоє небо
Я до тебе, я до тебе, я до тебе,

Отак іду собі туди

І ми ховалися в будинках на подолі
І ми ховалися по далі від людей
Без парасолі
А далі ти не знала де себе подіти
А далі я не знав залишитись чи ні
Дорослі літи

Приспів

Програш: Gm A# G# Cm - 4 рази.
Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_818575'), datetime('now')),datetime('now'));
