INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_82373','Боже, мій Боже','Музика: Богдан Трояновський, Ярина Трояновська Слова: Богдан Трояновський, Ярина Трояновська','uk','ukraine_1991',NULL,NULL,'1. Співаник для таборів Марійської Дружини 2. пісенник для християнської молоді "Боже, мій Боже, з тобою пісня..."',NULL,'Приспів:
C
Боже, мій Боже, з тобою пісня,
З Тобою правда і надія,
З Тобою в смутку перемога,
З Тобою радісна дорога.

C
Коли життя несе тривоги,
Коли гнітить тебе неспокій,
Коли хтось хоче залякати,
І ти не знаєш, де сховатись...
Гітару в свої руки візьмеш,
Чужий світ десь позаду лишиш,
На тебе інші вже чекають,
Разом з тобою заспівають...

Приспів.

Світ нас чарує, світ нас манить,
Карєра, гроші і розваги.
А я усе це залишаю,
Бо я багатства інші маю.
Блакитне небо, білі хмари,
Високі гори, квіти, трави,
Гітари звук, знайома пісня,
І в серці радісна молитва.

Приспів.

Про правду люди забувають,
Лице під маскою ховають,
А я не хочу фальшувати,
Життя обманом будувати.
Мені чужі сум і тривога,
На мене жде нова дорога,
Я хочу радісно співати,
Я хочу з Богом мандрувати.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_82373'), datetime('now')),datetime('now'));
