INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_825474','На поточку-м прала','Українська народна пісня. Виконує: Гудаки','uk','ukraine_before_1917',NULL,NULL,'З пам''яті за емігрантськими аудіозаписами 1970-х.','Пісня поширена як в Україні, так і в діаспорі.','На поточку-м прала,
На вербочку-м клала,
Поможи ми, пане боже,
Що-м собі думала,
Em        H7Em
Що-м собі думала.

Я собі думала
Хлопця молодого,
А мене віддали
За діда старого.        |(2)

Як ня віддавали,
То так і казали:
- Аби-сь, моя доню,
Діда шанувала.          |(2)

Я діда шаную,
Шанувати мушу.
- Поможи ми, пане боже,
Візьми з діда душу.     |(2)

Візьми з діда душу
Та й повісь на грушу,
Аби старим знати,
Як молоду брати.        |(2)

На поточку-м прала,
На вербочку-м клала,
Поможи ми, пане боже,
Що-м собі думала.       |(2)','[''pisni.org.ua'', ''cat:boykivski'', ''Пісні з Бойківщини'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_825474'), datetime('now')),datetime('now'));
