INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8265474','Край Палестина - земля благословенна',NULL,'uk','ukraine_1991',NULL,NULL,'http://songs.fleita.com/file.php?id=1076','Виконують Брати Давидюки.','Край Палестина - земля благословенна,
Там де був, народився наш Ісус.
Край том всім знаний, завжди величний, славний,
Сяйвом з неба покритий був кругом.

О, незабутня є та історія,
Як наш Спаситель пролив був кров.
О, кров, та дорогоцінна
Сина Божого Ісуса Христа.

Мури і стіни того Єрусалиму
Свідчать про всі діла й чуда Христа,
Як сильно збитий, на хрест Він був прибитий,
Випив чашу гірку за нас до дна.

Це незабутня для нас є та історія,
Як жив, учив людей колись Христос.
В садах оливних серед гір тих чарівних
Лились слова Його до тисячей.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8265474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8265474','Край Палестина - земля благословенна','Край Палестина - земля благословенна,
Там де був, народився наш Ісус.
Край том всім знаний, завжди величний, славний,
Сяйвом з неба покритий був кругом.

О, незабутня є та історія,
Як наш Спаситель пролив був кров.
О, кров, та дорогоцінна
Сина Божого Ісуса Христа.

Мури і стіни того Єрусалиму
Свідчать про всі діла й чуда Христа,
Як сильно збитий, на хрест Він був прибитий,
Випив чашу гірку за нас до дна.

Це незабутня для нас є та історія,
