INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_828171','А там долов під Липою','(Шість Загадок). Українська народна пісня. Виконує: Юлія Дошна','uk','ukraine_before_1917',NULL,NULL,'Самвидавний туристський пісенник: Там на Лемковині помедже горами. - Літо 1981.','Вказаний у джерелі пісенник створений українцем з Польщі Лехом Ляхом. Ймовірно, що обробка тексту й мелодії, підбір акордів здійснені ним. Пісня загальноукраїнська, записана на Лемківщині. Варіант цієї пісні під назвою "А там долом, під калиною" виконує Юлія Дошна. Пара-Непара — залицяння, любощі: Загадки. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Були Світилки Яснії Зірки. Качата-Гусята усі Гори вкрили. Сім Загадок загадаю. А хто любит чужу жену. Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції.','А там долов під Липою
Стоїт жовнір з Дівчиною

Стоїт стоїт розмовляє
За рученьку потискає

Ти Дівчино ти Молода
Відгадай мі Шіст Загадок *

Як відгадаш моя будеш,
Не відгадаш дурнов будеш

А што сходит без Насіння
А што росте без Коріння

А што грає Голос має
А што плаче Слез не має

А што біжит без прогону
А хто любит чужу жену

Я Молода я всьо знаю
Я всьо тобі відгадаю

Камін росте без Коріння
Сонце сходит без Насіння

Скрипка грає Голос має
Серце плаче Слез не має

Вода біжит без прогону
Жовнір любит чужу жену
Акорди:
А там долов під Липою
А там долов під Липою
Стоїт жовнір з Дівчиною
Стоїт жовнір з Дівчиною **
*Варіант:
